// UploadVideo registers a new video in the DB and enqueues it for processing.
func (r *mutationResolver) UploadVideo(ctx context.Context, title string, s3Key string) (*model.Video, error) {
	var id int
	err := r.DB.Pool.QueryRow(ctx,
		`INSERT INTO videos (title, s3_key, status) VALUES ($1, $2, 'queued') RETURNING id`,
		title, s3Key,
	).Scan(&id)
	if err != nil {
		return nil, fmt.Errorf("insert video: %w", err)
	}

	// Publish Kafka event so the worker processor picks it up.
	type processEvent struct {
		VideoID string `json:"video_id"`
		S3Key   string `json:"s3_key"`
	}
	if r.Producer != nil {
		if err := r.Producer.ProduceEvent(ctx, strconv.Itoa(id), processEvent{
			VideoID: strconv.Itoa(id),
			S3Key:   s3Key,
		}); err != nil {
			return nil, fmt.Errorf("enqueue video: %w", err)
		}
	}

	return r.queryVideo(ctx, strconv.Itoa(id))
}

// DeleteVideo removes a video and its cascading chat data.
func (r *mutationResolver) DeleteVideo(ctx context.Context, id string) (bool, error) {
	tag, err := r.DB.Pool.Exec(ctx, `DELETE FROM videos WHERE id=$1`, id)
	if err != nil {
		return false, fmt.Errorf("delete video: %w", err)
	}
	return tag.RowsAffected() > 0, nil
}

