// SendMessage routes a user message through the VLM and persists both turns.
func (r *mutationResolver) SendMessage(ctx context.Context, sessionID string, message string) (*model.ChatMessage, error) {
	// 1. Look up the video_id for this session.
	var videoID int
	err := r.DB.Pool.QueryRow(ctx,
		`SELECT video_id FROM chat_sessions WHERE id=$1`, sessionID,
	).Scan(&videoID)
	if err != nil {
		return nil, fmt.Errorf("session not found: %w", err)
	}

	// 2. Fetch the stored video analysis (the VLM's initial deep-dive).
	var analysis string
	_ = r.DB.Pool.QueryRow(ctx,
		`SELECT COALESCE(analysis, '') FROM videos WHERE id=$1`, videoID,
	).Scan(&analysis)

	if analysis == "" {
		return nil, fmt.Errorf("video analysis not ready yet — please wait for processing to complete")
	}

	// 3. Load prior chat history for this session (ordered by creation time).
	rows, err := r.DB.Pool.Query(ctx,
		`SELECT role, content FROM chat_messages WHERE session_id=$1 ORDER BY id ASC`,
		sessionID,
	)
	if err != nil {
		return nil, fmt.Errorf("load history: %w", err)
	}
	var history []worker.ChatTurn
	for rows.Next() {
		var turn worker.ChatTurn
		rows.Scan(&turn.Role, &turn.Content)
		history = append(history, turn)
	}
	rows.Close()

	// 4. Persist the user message.
	_, err = r.DB.Pool.Exec(ctx,
		`INSERT INTO chat_messages (session_id, role, content) VALUES ($1, 'user', $2)`,
		sessionID, message,
	)
	if err != nil {
		return nil, fmt.Errorf("save user message: %w", err)
	}

	// 5. Call the VLM.
	reply, err := worker.ChatWithVideo(analysis, history, message)
	if err != nil {
		return nil, fmt.Errorf("VLM call failed: %w", err)
	}

	// 6. Persist the assistant reply and return it.
	var msgID int
	var createdAt string
	err = r.DB.Pool.QueryRow(ctx,
		`INSERT INTO chat_messages (session_id, role, content) VALUES ($1, 'assistant', $2) RETURNING id, created_at::text`,
		sessionID, reply,
	).Scan(&msgID, &createdAt)
	if err != nil {
		return nil, fmt.Errorf("save assistant message: %w", err)
	}

	return &model.ChatMessage{
		ID:        strconv.Itoa(msgID),
		SessionID: sessionID,
		Role:      "assistant",
		Content:   reply,
		CreatedAt: createdAt,
	}, nil
}

