// Videos returns all videos, newest first.
func (r *queryResolver) Videos(ctx context.Context) ([]*model.Video, error) {
	rows, err := r.DB.Pool.Query(ctx,
		`SELECT id, title, status, COALESCE(summary,''), COALESCE(analysis,''), created_at::text
		 FROM videos ORDER BY id DESC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var videos []*model.Video
	for rows.Next() {
		v := &model.Video{}
		var id int
		rows.Scan(&id, &v.Title, &v.Status, &v.Summary, &v.Analysis, &v.CreatedAt)
		v.ID = strconv.Itoa(id)
		videos = append(videos, v)
	}
	return videos, nil
}

// Video returns a single video by ID.
